 1	import * as React from 'react';
 2	import { getName } from '@odf/shared/selectors';
 3	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 4	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
 5	import * as _ from 'lodash-es';
 6	import { SearchInput, SearchInputProps } from '@patternfly/react-core';
 7	
 8	type ListFilterProps = {
 9	  data: K8sResourceCommon[];
10	  loaded: boolean;
11	  dataFilter?: (resource: K8sResourceCommon) => boolean;
12	  textInputProps?: Omit<SearchInputProps, 'value' | 'onChange' | 'onClear'>;
13	  children: (filteredData: K8sResourceCommon[]) => React.ReactNode;
14	};
15	
16	export const ListFilter: React.FC<ListFilterProps> = ({
17	  data,
18	  loaded,
19	  dataFilter,
20	  textInputProps,
21	  children,
22	}) => {
23	  const { t } = useCustomTranslation();
24	  const [input, setInput] = React.useState('');
25	
26	  const filteredData = React.useMemo(() => {
27	    if (!input) return data;
28	    const resourceFilter =
29	      dataFilter ||
30	      ((resource: K8sResourceCommon): boolean =>
31	        _.toLower(getName(resource)).includes(_.toLower(input)));
32	    return (data ?? []).filter(resourceFilter);
33	  }, [input, data, dataFilter]);
34	
35	  const onChange = (
36	    inputValue: string | React.FormEvent<HTMLInputElement>
37	  ): void =>
38	    setInput(
39	      typeof inputValue === 'string'
40	        ? inputValue
41	        : (inputValue.target as HTMLInputElement)?.value
42	    );
43	
44	  return (
45	    <>
46	      {loaded && !_.isEmpty(data) && (
47	        <SearchInput
48	          {...textInputProps}
49	          placeholder={textInputProps?.placeholder || t('Search by name...')}
50	          value={input}
51	          onChange={onChange}
52	          onClear={(): void => onChange('')}
53	        />
54	      )}
55	      {children(filteredData)}
56	    </>
57	  );
58	};

